esqlQuery.esql:
// Alert when the OpenTelemetry Collector reports non-zero rate of failed log record exports.
//
// metrics.otelcol_exporter_send_failed_log_records is a cumulative counter; RATE() yields
// per-bucket increases. TS is used for time-series metrics (counter resets handled by the TS pipeline).
//
// Scope: metrics-collectortelemetry* and collectortelemetry.otel dataset to avoid mixing with
// unrelated metrics-* streams.
//
// Grouping: service.name and service.instance.id help identify which collector instance fails.
//
// Tuning: raise the threshold (e.g. failed_log_records_rate > N) or increase alert delay
// to reduce noise from brief blips.
//
TS metrics-collectortelemetry*
| WHERE data_stream.dataset == "collectortelemetry.otel"
| STATS failed_log_records_rate = SUM(RATE(metrics.otelcol_exporter_send_failed_log_records)) BY service.name, service.instance.id
| WHERE failed_log_records_rate > 0
| SORT failed_log_records_rate DESC
